// AUTO-GENERATED DRAFT SCREEN: TransactionHistoryScreen

import React from 'react';
import { useQuery } from '@tanstack/react-query'; // Placeholder for tRPC hook
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';

// Define types for transaction data
interface Transaction {
  id: string;
  date: string;
  type: 'deposit' | 'withdrawal' | 'transfer' | 'exchange';
  amount: number;
  currency: string;
  status: 'completed' | 'pending' | 'failed';
}

// Placeholder for tRPC query hook
// In a real application, this would be generated by tRPC
const trpc = {
  crypto: {
    getTransactionHistory: {
      useQuery: (params: { page: number; limit: number; type?: string; search?: string }) => {
        // Mock data for demonstration
        const mockTransactions: Transaction[] = Array.from({ length: 50 }, (_, i) => ({
          id: `txn-${i + 1}`,
          date: new Date(Date.now() - i * 86400000).toISOString().split('T')[0],
          type: ['deposit', 'withdrawal', 'transfer', 'exchange'][i % 4] as any,
          amount: parseFloat((Math.random() * 1000 + 10).toFixed(2)),
          currency: ['SKY', 'USD', 'EUR'][i % 3],
          status: ['completed', 'pending', 'failed'][i % 3] as any,
        }));

        const filteredTransactions = mockTransactions.filter(txn => {
          if (params.type && txn.type !== params.type) return false;
          if (params.search && !txn.id.includes(params.search) && !txn.currency.includes(params.search)) return false;
          return true;
        });

        const start = (params.page - 1) * params.limit;
        const end = start + params.limit;
        const data = filteredTransactions.slice(start, end);
        const total = filteredTransactions.length;

        return {
          data: { transactions: data, totalPages: Math.ceil(total / params.limit) },
          isLoading: false,
          isError: false,
          error: null,
        };
      },
    },
  },
};

const TransactionHistoryScreen: React.FC = () => {
  const [page, setPage] = React.useState(1);
  const [limit, setLimit] = React.useState(10);
  const [transactionType, setTransactionType] = React.useState<string | undefined>(undefined);
  const [searchTerm, setSearchTerm] = React.useState<string>('');

  const { data, isLoading, isError, error } = trpc.crypto.getTransactionHistory.useQuery({
    page,
    limit,
    type: transactionType,
    search: searchTerm,
  });

  const transactions = data?.transactions || [];
  const totalPages = data?.totalPages || 1;

  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <p>Loading transaction history...</p>
      </div>
    );
  }

  if (isError) {
    return (
      <div className="flex items-center justify-center min-h-screen text-red-500">
        <p>Error: {error?.message || 'Failed to load transaction history.'}</p>
      </div>
    );
  }

  return (
    <div className="container mx-auto py-8 px-4 dark:bg-gray-900 dark:text-gray-100">
      <Card className="w-full">
        <CardHeader>
          <CardTitle className="text-3xl font-bold">Transaction History</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="flex flex-col md:flex-row gap-4 mb-6 items-end">
            <div className="flex-1">
              <Label htmlFor="search">Search</Label>
              <Input
                id="search"
                type="text"
                placeholder="Search by ID or currency..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full"
              />
            </div>
            <div className="w-full md:w-48">
              <Label htmlFor="type-filter">Transaction Type</Label>
              <Select onValueChange={(value) => setTransactionType(value === 'all' ? undefined : value)}>
                <SelectTrigger id="type-filter" className="w-full">
                  <SelectValue placeholder="Filter by type" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Types</SelectItem>
                  <SelectItem value="deposit">Deposit</SelectItem>
                  <SelectItem value="withdrawal">Withdrawal</SelectItem>
                  <SelectItem value="transfer">Transfer</SelectItem>
                  <SelectItem value="exchange">Exchange</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <Button onClick={() => { setPage(1); /* Trigger refetch */ }} className="w-full md:w-auto">Apply Filters</Button>
          </div>

          <div className="overflow-x-auto">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>ID</TableHead>
                  <TableHead>Date</TableHead>
                  <TableHead>Type</TableHead>
                  <TableHead className="text-right">Amount</TableHead>
                  <TableHead>Currency</TableHead>
                  <TableHead>Status</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {transactions.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={6} className="text-center py-4">
                      No transactions found.
                    </TableCell>
                  </TableRow>
                ) : (
                  transactions.map((transaction) => (
                    <TableRow key={transaction.id}>
                      <TableCell className="font-medium">{transaction.id}</TableCell>
                      <TableCell>{transaction.date}</TableCell>
                      <TableCell>{transaction.type}</TableCell>
                      <TableCell className="text-right">{transaction.amount.toFixed(2)}</TableCell>
                      <TableCell>{transaction.currency}</TableCell>
                      <TableCell>
                        <span
                          className={`px-2 py-1 rounded-full text-xs font-semibold
                            ${transaction.status === 'completed' ? 'bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200'
                            : transaction.status === 'pending' ? 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900 dark:text-yellow-200'
                            : 'bg-red-100 text-red-800 dark:bg-red-900 dark:text-red-200'}
                          `}
                        >
                          {transaction.status.charAt(0).toUpperCase() + transaction.status.slice(1)}
                        </span>
                      </TableCell>
                    </TableRow>
                  ))
                )}
              </TableBody>
            </Table>
          </div>

          <div className="flex justify-between items-center mt-6">
            <Button
              variant="outline"
              onClick={() => setPage((prev) => Math.max(1, prev - 1))}
              disabled={page === 1 || isLoading}
            >
              Previous
            </Button>
            <span className="text-sm">
              Page {page} of {totalPages}
            </span>
            <Button
              variant="outline"
              onClick={() => setPage((prev) => Math.min(totalPages, prev + 1))}
              disabled={page === totalPages || isLoading}
            >
              Next
            </Button>
          </div>
        </CardContent>
      </Card>
    </div>
  );
};

export default TransactionHistoryScreen;
